examples.example:
Building lists unnecessarily:
# DON'T: Eager evaluation uses more memory
def enumerate_months(...) -> tuple[date, ...]:
    months = []
    while ...:
        months.append(current)
    return tuple(months)

example.code:
from collections.abc import Iterator from datetime import date
def enumerate_months(start: date, end: date) -> Iterator[date]: """Generate month boundaries lazily.""" current = start.replace(day=1) end_month = end.replace(day=1) while current <= end_month: yield current current = current + relativedelta(months=1)
# Caller decides when to materialize months_list = list(enumerate_months(start, end)) # Only if needed
